import{_ as t,o as a,c as r,a2 as e}from"./chunks/framework.Pywvta2k.js";const g=JSON.parse('{"title":"徐文兵","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/05-近现代/04-徐文兵.md","filePath":"tcm-data/05-近现代/04-徐文兵.md","lastUpdated":1781084559000}'),l={name:"tcm-data/05-近现代/04-徐文兵.md"};function n(s,o,i,u,c,h){return a(),r("div",null,[...o[0]||(o[0]=[e('<h1 id="徐文兵" tabindex="-1">徐文兵 <a class="header-anchor" href="#徐文兵" aria-label="Permalink to &quot;徐文兵&quot;">​</a></h1><blockquote><p>徐文兵（1966年生），北京人 当代中医科普第一人 代表作：《字里藏医》《黄帝内经家用说明书》《知己》</p></blockquote><hr><h2 id="一、基本信息" tabindex="-1">一、基本信息 <a class="header-anchor" href="#一、基本信息" aria-label="Permalink to &quot;一、基本信息&quot;">​</a></h2><ul><li><strong>字号</strong>：名小周，字文兵</li><li><strong>师承</strong>：裴永清（伤寒大家）</li><li><strong>经历</strong>：北京中医药大学毕业，原中国中医科学院医生，后创办&quot;厚朴中医学堂&quot;</li><li><strong>节目</strong>：与梁冬对话《黄帝内经》系列（中国之声，影响极大）</li></ul><hr><h2 id="二、核心理论" tabindex="-1">二、核心理论 <a class="header-anchor" href="#二、核心理论" aria-label="Permalink to &quot;二、核心理论&quot;">​</a></h2><h3 id="_1-从汉字解中医" tabindex="-1">1. 从汉字解中医 <a class="header-anchor" href="#_1-从汉字解中医" aria-label="Permalink to &quot;1. 从汉字解中医&quot;">​</a></h3><p>徐文兵最独特的贡献是：<strong>通过汉字的本源含义来阐释中医概念</strong>：</p><ul><li><strong>&quot;健&quot;</strong> = 强有力（力气）→ 侧重形体</li><li><strong>&quot;康&quot;</strong> = 通达（经络通）→ 侧重功能</li><li><strong>&quot;病&quot;</strong> = 形变（器质性改变）→ 重</li><li><strong>&quot;症&quot;</strong> = 表象（功能性改变）→ 轻</li></ul><h3 id="_2-恢复知觉" tabindex="-1">2. 恢复知觉 <a class="header-anchor" href="#_2-恢复知觉" aria-label="Permalink to &quot;2. 恢复知觉&quot;">​</a></h3><blockquote><p><strong>「现在的人，失去知觉了。不知饥饱，不知寒热，不知疲劳。」</strong></p></blockquote><p>治疗的第一步，是<strong>恢复人的知觉</strong>——知道饿、知道困、知道冷热。</p><h3 id="_3-中医生活化" tabindex="-1">3. 中医生活化 <a class="header-anchor" href="#_3-中医生活化" aria-label="Permalink to &quot;3. 中医生活化&quot;">​</a></h3><p>徐文兵的核心贡献是<strong>把中医从书本上带进了生活</strong>：</p><ul><li>怎么吃、怎么睡、怎么呼吸</li><li>为什么不能喝冰水</li><li>为什么水果不能当饭吃</li><li>为什么春季要养肝、秋季要养肺</li></ul><h3 id="_4-贵生思想" tabindex="-1">4. 贵生思想 <a class="header-anchor" href="#_4-贵生思想" aria-label="Permalink to &quot;4. 贵生思想&quot;">​</a></h3><blockquote><p><strong>「贵生，就是尊重生命。不尊重生命的人，不配学医。」</strong></p></blockquote><hr><h2 id="三、经典名言" tabindex="-1">三、经典名言 <a class="header-anchor" href="#三、经典名言" aria-label="Permalink to &quot;三、经典名言&quot;">​</a></h2><blockquote><p><strong>「健康的人，是恢复知觉的人。」</strong></p></blockquote><blockquote><p><strong>「现在的人，失去知觉了。不知饥饱，不知寒热，不知疲劳。」</strong></p></blockquote><blockquote><p><strong>「食饮有节，起居有常，不妄作劳——这就是最好的养生。」</strong></p></blockquote><blockquote><p><strong>「为什么现在的人越来越虚？因为欲望太多，消耗太大。」</strong></p></blockquote><blockquote><p><strong>「中医不是治病的，是治人的。」</strong></p></blockquote><blockquote><p><strong>「学中医，要从认字开始。」</strong></p></blockquote><blockquote><p><strong>「生命的本质是气。有气则生，无气则死。」</strong></p></blockquote><blockquote><p><strong>「春生夏长，秋收冬藏。逆之则伤。」</strong></p></blockquote><hr><h2 id="四、对普光-普明的指导" tabindex="-1">四、对普光/普明的指导 <a class="header-anchor" href="#四、对普光-普明的指导" aria-label="Permalink to &quot;四、对普光/普明的指导&quot;">​</a></h2><ul><li><strong>普光</strong>：恢复知觉——腰凉了知道保暖，渴了知道不是真热，前胸出汗多知道要收敛运动强度</li><li><strong>普明</strong>：恢复知觉——累了知道要休息，烦躁了知道是肝火，口干知道是虚火不是真热</li></ul><hr><p><em>本条目为精简框架版。可扩展至徐文兵《黄帝内经说什么》系列精要、厚朴教学体系、饮食养生专题等。</em></p>',33)])])}const d=t(l,[["render",n]]);export{g as __pageData,d as default};
